      vi: { term: "Hiện tượng đọc ảo", explanation: "Hiện tượng một giao dịch truy vấn tập hợp bản ghi nhiều lần nhưng nhận được kết quả khác nhau do có dòng mới được chèn.", needsReview: true },
      fr: { term: "Lecture fantôme", explanation: "Anomalie se produisant lorsqu'une transaction réexécute une requête et obtient des lignes supplémentaires insérées par ailleurs.", needsReview: true },
      aliases: ["Phantom Read"],
      related: ["database","repeatable_read"],
      example: {"sql":"Phantom reads are only prevented in the SERIALIZABLE isolation level in standard SQL."},
