      ja: { term: "直接メモリアクセス", kana: "チョクセツメモリアクセス", note: "CPU を介さずに、周辺機器と主記憶装置（RAM）の間で直接高速なデータ転送を行うハードウェアの仕組み。DMA と呼ばれる。" },
      zh: { term: "直接内存存取", explanation: "外设与计算机系统内存之间进行高速数据传输，中途无需经过 CPU 介入和干预的一种数据通道控制机制，简称 DMA。" },
      en: { term: "Direct Memory Access", explanation: "A feature of computer systems that allows certain hardware subsystems to access main system memory independently of the central processing unit." },
