      fr: {"term":"Partage de ressources entre origines multiples","explanation":"Mécanisme (CORS) de sécurité web par en-têtes HTTP autorisant ou bloquant l'accès à des ressources situées sur un autre domaine。","needsReview":true},
      aliases: ["CORS","Cross-Origin Resource Sharing"],
